-- 6. Swale × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'swale',
  'Social media in Swale operates through tightly knit local communities that vary dramatically across the borough. Faversham''s social media scene is driven by food bloggers, heritage enthusiasts, and a creative community that shares and amplifies businesses they love. The town''s food reputation has been built as much on Instagram and food blogs as on traditional media. Sittingbourne''s social media is community-group driven, with active Facebook groups where residents recommend trades, services, and local businesses daily. On the Isle of Sheppey, social media is often the primary business presence, with many island enterprises operating exclusively through Facebook pages. Each zone demands a different social media strategy, and a Swale business without the right presence for its zone is missing the conversations that drive local commerce.',
  'Swale''s social media landscape reflects the borough''s three-zone structure. Faversham has a strong Instagram and food blog ecosystem driven by the town''s culinary reputation. Shepherd Neame brewery events, Standard Quay markets, and Faversham Creek dining all generate social content. Sittingbourne is Facebook-dominant, with resident community groups serving as the primary recommendation platform for trades and services. The Isle of Sheppey has extremely active Facebook community groups that function as the island''s informal business directory. Google reviews influence discovery across all three zones.',
  'Social media maturity varies enormously across Swale. Faversham''s food and creative businesses often maintain good Instagram presence but may lack Facebook community engagement. Sittingbourne businesses frequently have dormant Facebook pages with no strategy for community group participation. Sheppey businesses tend to rely entirely on Facebook, often using personal profiles rather than business pages, missing the features and credibility that proper business accounts provide.',
  'We set up social media for Swale businesses based on the platform dynamics of their specific zone. Faversham food businesses get Instagram-first strategies built for food photography and influencer engagement. Sittingbourne trades get Facebook profiles optimised for community group recommendations. Sheppey businesses get proper business pages migrated from personal profiles, with branding and content that projects professionalism. Every profile is branded consistently and optimised for the social media ecosystem that drives commerce in each Swale zone.',
  '{"population": 152000, "growth": "Three distinct social media ecosystems within one borough", "business_districts": ["Faversham food scene", "Sittingbourne residential community", "Isle of Sheppey", "Standard Quay"], "key_fact": "Faversham''s food reputation built significantly through Instagram and food blog ecosystem"}',
  '[{"title": "Missing from Faversham''s food influencer ecosystem", "description": "Faversham''s growing food reputation is driven by Instagram food bloggers, local influencers, and a creative community that shares quality experiences. A Faversham food business without an active, well-branded Instagram profile is invisible to this ecosystem. When a food blogger visits Standard Quay or the Creek, they tag and share the businesses that present well online."}, {"title": "Invisible in Sittingbourne''s community recommendation groups", "description": "When a Sittingbourne resident posts in a Facebook community group asking for a plumber, painter, or restaurant recommendation, your business cannot be tagged or found if it has no Facebook presence. These groups generate genuine customer referrals daily, and businesses without properly set up profiles miss every one of them."}, {"title": "Sheppey businesses using personal profiles instead of business pages", "description": "Many Isle of Sheppey businesses operate through the owner''s personal Facebook profile rather than a proper business page. This limits discoverability, prevents access to business features like reviews and advertising, and appears unprofessional to potential customers who are already cautious about Sheppey''s business offering."}]',
  '[{"title": "Instagram-first setup for Faversham food and creative businesses", "description": "We build and optimise your Instagram business profile for Faversham''s food and creative ecosystem. Professional bio, visual grid strategy aligned to the town''s artisanal aesthetic, hashtag research for Faversham food and heritage tags, and content templates that maintain quality alongside the food bloggers and influencers who drive the town''s reputation."}, {"title": "Community-group-ready Facebook for Sittingbourne trades", "description": "We build Facebook business profiles optimised for engagement in Sittingbourne''s community groups. Professional branding, complete service information, portfolio imagery, and review optimisation ensure your profile converts recommendation requests into enquiries from the borough''s largest residential population centre."}, {"title": "Professional business page migration for Sheppey enterprises", "description": "We migrate Sheppey businesses from personal Facebook profiles to properly set up business pages, transferring followers and content. Professional branding, accurate information, review capability, and advertising access transform your social presence from amateur to professional, projecting the quality that attracts customers to island businesses."}]',
  '[{"question": "Which social media platforms should my Swale business be on?", "answer": "This depends on your zone. Faversham food and hospitality businesses need Instagram first. Sittingbourne trades and services need Facebook for community group engagement. Sheppey businesses need a proper Facebook business page at minimum. We recommend the right platforms based on where your specific Swale customers spend time online."}, {"question": "Can you help me engage with Faversham''s food blogger community?", "answer": "We set up your Instagram profile to attract food blogger attention: professional imagery, consistent visual style, relevant hashtags, and tagged content strategy. We also provide guidance on engaging with local influencers. The Faversham food scene is collaborative, and businesses with professional social presence get shared and recommended."}, {"question": "How do I move my Sheppey business from a personal profile to a business page?", "answer": "We handle the full migration process: creating a professional business page, transferring followers, populating with branded content and accurate information, and setting up review capability. The transition is seamless for your existing followers while dramatically improving your professional appearance and business capabilities."}, {"question": "How important are Google reviews for Swale businesses?", "answer": "Very important across all three zones. Google reviews directly influence your local search ranking and are often the deciding factor for customers comparing options. We set up your Google Business Profile with optimised categories for your Swale zone and implement a review generation strategy to build social proof."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
